import {
  AgenticDeepReadFormFields,
  RetrievalModeFormField,
} from '@/components/agentic-deepread-item';
import { Collapse } from '@/components/collapse';
import { CrossLanguageFormField } from '@/components/cross-language-form-field';
import { FormContainer } from '@/components/form-container';
import { KnowledgeBaseFormField } from '@/components/knowledge-base-item';
import { RAGFlowFormItem } from '@/components/ragflow-form';
import { RerankFormFields } from '@/components/rerank';
import { SimilaritySliderFormField } from '@/components/similarity-slider';
import { TopNFormField } from '@/components/top-n-item';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Textarea } from '@/components/ui/textarea';
import { UseKnowledgeGraphFormField } from '@/components/use-knowledge-graph-item';
import { RetrievalMode } from '@/constants/agentic-deepread';
import { zodResolver } from '@hookform/resolvers/zod';
import { memo, useEffect, useMemo } from 'react';
import { useForm, useFormContext, useWatch } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { z } from 'zod';
import { initialRetrievalValues } from '../../constant';
import { useWatchFormChange } from '../../hooks/use-watch-form-change';
import { INextOperatorForm } from '../../interface';
import { FormWrapper } from '../components/form-wrapper';
import { Output } from '../components/output';
import { PromptEditor } from '../components/prompt-editor';
import { useValues } from './use-values';

export const RetrievalPartialSchema = {
  similarity_threshold: z.coerce.number(),
  keywords_similarity_weight: z.coerce.number(),
  top_n: z.coerce.number(),
  top_k: z.coerce.number(),
  kb_ids: z.array(z.string()),
  rerank_id: z.string(),
  empty_response: z.string(),
  cross_languages: z.array(z.string()),
  use_kg: z.boolean(),
  retrieval_mode: z.nativeEnum(RetrievalMode),
  agentic_deepread: z.object({
    override_dataset_defaults: z.boolean(),
    candidate_doc_topn: z.coerce.number(),
    agent_max_rounds: z.coerce.number(),
    retrieve_strategy: z.enum(['auto', 'bm25', 'hybrid']),
    retrieve_topk: z.coerce.number(),
    evidence_cap: z.coerce.number(),
    neighbor_window_up: z.coerce.number(),
    neighbor_window_down: z.coerce.number(),
  }),
};

export const FormSchema = z.object({
  query: z.string().optional(),
  ...RetrievalPartialSchema,
});
type FormSchemaType = z.infer<typeof FormSchema>;

export function EmptyResponseField() {
  const { t } = useTranslation();
  const form = useFormContext();

  return (
    <FormField
      control={form.control}
      name="empty_response"
      render={({ field }) => (
        <FormItem>
          <FormLabel tooltip={t('chat.emptyResponseTip')}>
            {t('chat.emptyResponse')}
          </FormLabel>
          <FormControl>
            <Textarea
              placeholder={t('common.namePlaceholder')}
              {...field}
              autoComplete="off"
              rows={4}
            />
          </FormControl>
          <FormMessage />
        </FormItem>
      )}
    />
  );
}

function RetrievalForm({ node }: INextOperatorForm) {
  const { t } = useTranslation();

  const outputList = useMemo(() => {
    return [
      {
        title: 'formalized_content',
        type: initialRetrievalValues.outputs.formalized_content.type,
      },
    ];
  }, []);

  const defaultValues = useValues(node);

  const form = useForm<FormSchemaType>({
    defaultValues: defaultValues,
    resolver: zodResolver(FormSchema),
  });
  const retrievalMode = useWatch({
    control: form.control,
    name: 'retrieval_mode',
  });
  const isAgenticDeepRead = retrievalMode === RetrievalMode.AgenticDeepRead;

  useEffect(() => {
    form.setValue('use_kg', retrievalMode === RetrievalMode.Graph);
  }, [form, retrievalMode]);

  useWatchFormChange(node?.id, form);

  return (
    <Form {...form}>
      <FormWrapper>
        <FormContainer>
          <RAGFlowFormItem name="query" label={t('flow.query')}>
            <PromptEditor></PromptEditor>
          </RAGFlowFormItem>
          <KnowledgeBaseFormField showVariable></KnowledgeBaseFormField>
        </FormContainer>
        <Collapse title={<div>{t('flow.advancedSettings')}</div>}>
          <FormContainer>
            {!isAgenticDeepRead && (
              <SimilaritySliderFormField
                vectorSimilarityWeightName="keywords_similarity_weight"
                isTooltipShown
              ></SimilaritySliderFormField>
            )}
            {!isAgenticDeepRead && <TopNFormField></TopNFormField>}
            <RetrievalModeFormField name="retrieval_mode" />
            {isAgenticDeepRead && (
              <AgenticDeepReadFormFields baseName="agentic_deepread" />
            )}
            {!isAgenticDeepRead && <RerankFormFields></RerankFormFields>}
            <EmptyResponseField></EmptyResponseField>
            <CrossLanguageFormField name="cross_languages"></CrossLanguageFormField>
            {!isAgenticDeepRead && (
              <UseKnowledgeGraphFormField
                name="use_kg"
                disabled
              ></UseKnowledgeGraphFormField>
            )}
          </FormContainer>
        </Collapse>
        <Output list={outputList}></Output>
      </FormWrapper>
    </Form>
  );
}

export default memo(RetrievalForm);
